files.content:
:host {
  display: block;
  box-sizing: border-box;
  content-visibility: auto;
  contain-intrinsic-size: auto var(--dimension-size-800);
  -webkit-user-select: none;
  user-select: none;
}

:host(.message-host--group-middle),
:host(.message-host--group-last) {
  margin-block-start: calc(var(--dimension-space-050) - var(--dimension-space-300));
}

.message {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: end;
  gap: 0;
  width: 100%;
  box-sizing: border-box;
}

.message--outgoing {
  grid-template-columns: minmax(0, 1fr) auto;
}

.message__header:empty,
.message__footer:empty,
.message__actions:empty {
  display: none;
}

.message__actions:not(:empty) {
  margin-inline-start: var(--dimension-space-075);
}

.message__body {
  display: flex;
  flex-direction: column;
  min-width: 0;
  gap: var(--dimension-space-050);
}

.message--incoming .message__body {
  width: 100%;
}

.message--outgoing .message__body {
  align-items: flex-end;
}

.message--outgoing .message__header {
  display: none;
}

.message--system .message__body {
  align-items: center;
}

.message__header,
.message__footer,
.message__actions {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
}

.message__content {
  width: 100%;
  min-width: 0;
  -webkit-user-select: text;
  user-select: text;
}

.message--outgoing .message__content {
  display: flex;
  justify-content: flex-end;
}

.message__footer time {
  display: inline-flex;
}

.message--group-middle .message__header,
.message--group-last .message__header {
  display: none;
}

.message--group-first .message__footer,
.message--group-middle .message__footer {
  display: none;
}

import { Component, h, Host, Prop } from '@stencil/core';
import type {
  MessageDeliveryState,
  MessageDirection,
  MessageGroupPosition,
} from '../conversation-types';

const DELIVERY_LABELS: Record<MessageDeliveryState, string> = {
  sending: 'Sending',
  sent: 'Sent',
  delivered: 'Delivered',
  read: 'Read',
  failed: 'Failed to send',
};

@Component({
  tag: 'ds-message',
  styleUrl: 'Message.css',
  scoped: true,
})
export class Message {
  @Prop({ reflect: true }) messageId: string = '';
  @Prop({ reflect: true }) direction: MessageDirection = 'incoming';
  @Prop() groupPosition: MessageGroupPosition = 'single';
  @Prop() author: string = '';
  /** Keep author semantics while allowing products with self-evident roles to hide the visible label. */
  @Prop() showAuthor: boolean = true;
  /** ISO timestamp. */
  @Prop() timestamp: string = '';
  @Prop() deliveryState: MessageDeliveryState | undefined;
  @Prop() streaming: boolean = false;
  @Prop({ reflect: true }) scrollAnchor: boolean = false;

  private formattedTimestamp(): string {
    if (!this.timestamp) return '';
    const parsed = Date.parse(this.timestamp);
    if (Number.isNaN(parsed)) return this.timestamp;
    return new Intl.DateTimeFormat(undefined, {
      hour: 'numeric',
      minute: '2-digit',
    }).format(new Date(parsed));
  }

  render() {
    const delivery = this.deliveryState ? DELIVERY_LABELS[this.deliveryState] : '';
    const formattedTimestamp = this.formattedTimestamp();
    return (
      <Host
        class={`message-host--group-${this.groupPosition}`}
        data-message-id={this.messageId || undefined}
        data-scroll-anchor={this.scrollAnchor ? 'true' : undefined}
        aria-busy={this.streaming ? 'true' : undefined}
      >
        <article
          class={{
            message: true,
            [`message--${this.direction}`]: true,
            [`message--group-${this.groupPosition}`]: true,
          }}
          aria-label={this.author ? `Message from ${this.author}` : 'Message'}
        >
          <div class="message__body">
            <div class="message__header">
              <slot name="header" />
              {this.author && this.showAuthor ? (
                <ds-text as="span" variant="text-caption" emphasis color="primary">
                  {this.author}
                </ds-text>
              ) : null}
            </div>
            <div class="message__content">
              <slot />
            </div>
            <div class="message__footer">
              <slot name="footer" />
              {delivery ? (
                <ds-text
                  as="span"
                  variant="text-caption"
                  color={this.deliveryState === 'failed' ? 'negative' : 'secondary'}
                >
                  {delivery}
                </ds-text>
              ) : null}
              {formattedTimestamp ? (
                <time dateTime={this.timestamp}>
                  <ds-text as="span" variant="text-caption" color="secondary">
                    {formattedTimestamp}
                  </ds-text>
                </time>
              ) : null}
            </div>
          </div>
          <div class="message__actions">
            <slot name="actions" />
          </div>
        </article>
      </Host>
    );
  }
}
